fn read_matrix(n: i64) -> i64 = {
    let mat: i64 = vec_new();
    let total: i64 = n * n;
    for i in 0..total {
        vec_push(mat, read_int());
        ()
    };
    mat
};

fn get_elem(mat: i64, n: i64, row: i64, col: i64) -> i64 = {
    vec_get(mat, row * n + col)
};

fn spiral_order(mat: i64, n: i64) -> i64 = {
    let result: i64 = vec_new();
    let mut top: i64 = 0;
    let mut bottom: i64 = n - 1;
    let mut left: i64 = 0;
    let mut right: i64 = n - 1;

    while top <= bottom and left <= right {
        for i in left..(right + 1) {
            vec_push(result, get_elem(mat, n, top, i));
            ()
        };
        top = top + 1;

        if top <= bottom {
            for i in top..(bottom + 1) {
                vec_push(result, get_elem(mat, n, i, right));
                ()
            };
            right = right - 1;
            ()
        } else { () };

        if top <= bottom and left <= right {
            let mut i: i64 = right;
            while i >= left {
                vec_push(result, get_elem(mat, n, bottom, i));
                i = i - 1;
                ()
            };
            bottom = bottom - 1;
            ()
        } else { () };

        if top <= bottom and left <= right {
            let mut i: i64 = bottom;
            while i >= top {
                vec_push(result, get_elem(mat, n, i, left));
                i = i - 1;
                ()
            };
            left = left + 1;
            ()
        } else { () };
        ()
    };
    result
};

fn main() -> i64 = {
